Ajouter l’option suivante dans Program.cs lors de l’ajout des controleurs :
services.AddControllers()
    .ConfigureApiBehaviorOptions(options =>
    {
        options.SuppressModelStateInvalidFilter = true;
    });
Cela désactive globalement le filtre automatique. Si on veut seulement pour ce contrôleur, on peut supprimer [ApiController] ou utiliser un filtre personnalisé. Une autre solution : hériter d’un attribut qui supprime le comportement, mais ce n’est pas standard.

public class ValidationProduitAttribute : ValidationAttribute
{
    protected override ValidationResult IsValid(object value, ValidationContext validationContext)
    {
        var produit = (ProduitDto)validationContext.ObjectInstance;
        if (produit.TypeProduit == "service" && produit.DateLivraison != null)
            return new ValidationResult("Un service ne doit pas avoir de date de livraison.");
        if (produit.TypeProduit == "physique" && produit.DateLivraison == null)
            return new ValidationResult("Un produit physique doit avoir une date de livraison.");
        return ValidationResult.Success;
    }
}

// Utilisation :
[ValidationProduit]
public class ProduitDto
{
    public string TypeProduit { get; set; } // "service" ou "physique"
    public DateTime? DateLivraison { get; set; }
}
